import { Outlet } from "react-router-dom";
import { useState, useEffect } from "react";

import data from "../InteristingTexts.json"

import TypingText from "../Components/TextComponents/TypingText";
import image from "../Files/auth.png"

function IdentificationPage() {
  const [item, setItem] = useState(null);

  useEffect(() => {
    const randomIndex = Math.floor(Math.random() * data.length);
    setItem(data[randomIndex]);
  }, []);

  if (!item || item.text === null) return <div>Загрузка...</div>;
  return (
    <div className="container">
  <div className="image-wrapper">
    <img src={image} alt="" />
  </div>
  <div className="content">
    <Outlet/>
  </div>
</div>
  );
}

export default IdentificationPage;
